// Analyze campaign health metrics and flag issues
const stats = $input.first().json;

const totalSent = stats.total_sent || stats.sent_count || 0;
const totalOpened = stats.total_opened || stats.open_count || 0;
const totalReplied = stats.total_replied || stats.reply_count || 0;
const totalBounced = stats.total_bounced || stats.bounce_count || 0;
const totalSpam = stats.spam_count || 0;

const openRate = totalSent > 0 ? (totalOpened / totalSent * 100).toFixed(1) : 0;
const replyRate = totalSent > 0 ? (totalReplied / totalSent * 100).toFixed(1) : 0;
const bounceRate = totalSent > 0 ? (totalBounced / totalSent * 100).toFixed(1) : 0;
const spamRate = totalSent > 0 ? (totalSpam / totalSent * 100).toFixed(3) : 0;

// Health assessment
const alerts = [];

if (parseFloat(bounceRate) > 3) {
  alerts.push({ severity: 'critical', metric: 'bounce_rate', value: `${bounceRate}%`, threshold: '3%', action: 'Pause campaign immediately. Clean email list. Check verification.' });
}

if (parseFloat(spamRate) > 0.1) {
  alerts.push({ severity: 'critical', metric: 'spam_rate', value: `${spamRate}%`, threshold: '0.1%', action: 'STOP ALL SENDING. Review email copy. Check domain reputation.' });
}

if (parseFloat(openRate) < 25 && totalSent > 100) {
  alerts.push({ severity: 'warning', metric: 'open_rate', value: `${openRate}%`, threshold: '25%', action: 'Check subject lines. Verify deliverability. Test with mail-tester.com' });
}

if (parseFloat(replyRate) < 2 && totalSent > 200) {
  alerts.push({ severity: 'warning', metric: 'reply_rate', value: `${replyRate}%`, threshold: '2%', action: 'Review email copy. Check personalization quality. Consider ICP refinement.' });
}

const overallHealth = alerts.some(a => a.severity === 'critical') ? 'CRITICAL'
  : alerts.some(a => a.severity === 'warning') ? 'WARNING' 
  : 'HEALTHY';

return [{
  json: {
    overall_health: overallHealth,
    metrics: {
      total_sent: totalSent,
      total_opened: totalOpened,
      total_replied: totalReplied,
      total_bounced: totalBounced,
      total_spam: totalSpam,
      open_rate: `${openRate}%`,
      reply_rate: `${replyRate}%`,
      bounce_rate: `${bounceRate}%`,
      spam_rate: `${spamRate}%`
    },
    alerts,
    alert_count: alerts.length,
    checked_at: new Date().toISOString(),
    raw_stats: stats
  }
}];

// Format alert notification
const data = $input.first().json;
const alerts = data.alerts || [];
const metrics = data.metrics || {};

let message = `*Campaign Health: ${data.overall_health}*\n\n`;
message += `*Metrics:*\n`;
message += `- Sent: ${metrics.total_sent}\n`;
message += `- Open Rate: ${metrics.open_rate}\n`;
message += `- Reply Rate: ${metrics.reply_rate}\n`;
message += `- Bounce Rate: ${metrics.bounce_rate}\n`;
message += `- Spam Rate: ${metrics.spam_rate}\n\n`;

if (alerts.length > 0) {
  message += `*ALERTS:*\n`;
  for (const alert of alerts) {
    message += `[${alert.severity.toUpperCase()}] ${alert.metric}: ${alert.value} (threshold: ${alert.threshold})\n`;
    message += `  Action: ${alert.action}\n\n`;
  }
}

return [{ json: { message, channel: 'harvey-sdr-alerts', overall_health: data.overall_health } }];
